/* ---------------------------------------------------------------
 * Patch UI design tokens.
 *
 * Source of truth: packages/react/DESIGN.md.
 *
 * The system is a crisp-minimal, near-flat design language:
 *   - A near-black flat base in both themes (#0F0F13 dark, #FBFBFC light)
 *     with a subtle cool tint (blue lean, hue ~272) on all neutrals.
 *   - Two surface families that speak plainly: --layer-* is "lifted
 *     above base" (Card, Modal, popup, chrome), --fill-* is "tinted
 *     chip fill" (Toggle track, Badge, code chip). No "elevated" or
 *     "canvas" special names.
 *   - 1px hairline borders as the load-bearing separator.
 *   - A monochrome primary (consumers override --primary to inject brand).
 *   - Semantic status roles at fixed hex, theme-invariant.
 *   - Two type families: Inter Variable (all weights) and JetBrains Mono
 *     for code. Size and weight are separate axes: eight size tokens
 *     (micro/mini/small/regular/large/title3/title2/title1) composed at
 *     the call site with five weight tokens (light/normal/medium/
 *     semibold/bold). Line-height comes from element defaults.
 *   - Motion is fast: 75ms state, 150ms overlay, one easing curve.
 *
 * Layers:
 *   1. Raw runtime custom properties on :root / .dark.
 *   2. @theme inline bridge into Tailwind v4 utilities.
 *   3. @layer base global element typography defaults.
 *   4. @layer base thin-scrollbar defaults.
 * --------------------------------------------------------------- */

/* ---------------------------------------------------------------
 * Layer 1: Runtime theme values (light mode reference).
 * --------------------------------------------------------------- */
:root {
  /* Base is the page background: everything sits on it. layer-* is the
     "lifted above base" family (panels, cards, popups, chrome). fill-*
     is the "tinted chip/toggle fill" family. Neutrals carry a hair of
     cool chroma (blue lean, hue ~272) to match the reference; the
     tints are below the perception threshold on the last byte but
     shape the overall temperature. */
  --base:      #FBFBFC;

  /* Lifted rungs. layer-1 is the default panel surface: Card, Modal,
     Menu popup, Combobox popup, Tooltip, Select popup, Input, Table
     container, secondary Button chrome. layer-2 is a hover-adjacent
     step (secondary Button hover, Input hover companion). In light
     mode layer-1 is pure white so the lift reads against off-white
     base; in dark mode it lifts one rung above base. */
  --layer-1:   #FFFFFF;
  --layer-2:   #F7F7F9;

  /* Tinted chip/fill rungs. Toggle track, Badge neutral, code chip,
     Switch off-track, striped table hover, Skeleton, active pill Tab.
     These paint DEEPER than base in light mode: their job is a subtle
     darkened fill for indication, not a lift. */
  --fill-1:    #F5F5F8;
  --fill-2:    #EDEDF0;

  /* Adaptive interaction-state overlays. rgba (not opaque) so they
     darken whatever surface sits underneath: base, layer-1, fill-1,
     or a consumer's own background. Every transparent-at-rest control
     uses these for hover / selected fills so the state never
     disappears when it lands on a rung that happens to match. */
  --layer-hover:    rgba(0, 0, 0, 0.04);
  --layer-selected: rgba(0, 0, 0, 0.08);

  /* Hairlines. 1px borders carry every separation the layer/fill
     ladders can't. hairline-strong is for focused/hovered inputs and
     lifted card edges; hairline-tertiary is for nested content that
     already sits on a lifted surface. */
  --hairline:           rgba(0, 0, 0, 0.04);
  --hairline-strong:    rgba(0, 0, 0, 0.08);
  --hairline-tertiary:  rgba(0, 0, 0, 0.14);

  /* Ink (text) tiers. Same cool lean as the layer/fill ladder for
     temperature consistency. Icon color inherits from surrounding
     text color. */
  --ink:           #1D1D22;
  --ink-muted:     #545460;
  --ink-subtle:    #6E6E7C;
  --ink-tertiary:  #8E8EA0;

  /* Primary (monochrome). No chromatic brand hue ships. Consumers
     redefine these four tokens in a downstream layer to inject brand;
     every Button and focus-adjacent primitive inherits for free. */
  --primary:         var(--ink);
  --on-primary:      var(--base);
  /* Hover / active are proportional shifts off --primary via color-mix
     so a consumer's brand override on --primary automatically produces
     matching hover/active steps. Mixing with --base gives a "subtle
     move toward the background" that works in both themes: in light
     mode it lightens the dark primary, in dark mode it darkens the
     near-white primary. Avoids ink-muted/subtle which are much lighter
     tiers and would drop the button visibly on hover. */
  --primary-hover:   color-mix(in srgb, var(--primary), var(--base) 15%);
  --primary-active:  color-mix(in srgb, var(--primary), var(--base) 25%);

  /* Semantic status. Fixed hex, theme-invariant. -fg tokens carry the
     label color so fill and text invert together per theme without a
     callsite dark: variant. Hover/active shift lightness only. */
  --error:         #DC2626;
  --error-hover:   #B91C1C;
  --error-active:  #991B1B;
  --error-fg:      #FFFFFF;
  --warning:        #FDB203;
  --warning-hover:  #D69800;
  --warning-active: #A97007;
  --warning-fg:     #171717;
  --success:        #397C3B;
  --success-hover:  #2D602D;
  --success-active: #234A23;
  --success-fg:     #FFFFFF;

  /* Focus. 2px ring offset 2px outside the element border. The color
     reads --primary so the ring is monochrome ink by default and picks
     up a consumer's brand color for free when they override --primary
     -- every focused primitive gets a brand-colored ring without any
     callsite edits. The 2px + 2px pair sits clearly outside the
     component border rather than merging into it. */
  --focus-ring-color:  var(--primary);
  --focus-ring-width:  2px;
  --focus-ring-offset: 2px;

  /* Overlay scrim (dialog / drawer backdrop). */
  --scrim: rgba(0, 0, 0, 0.45);

  /* Radius. Five values, everything maps to one.
     radius-4 is reserved for very small controls (checkbox, radio thumb)
     where 6px would look proportionally too round. */
  --radius-4:    4px;
  --radius-6:    6px;
  --radius-12:   12px;
  --radius-16:   16px;
  --radius-full: 9999px;

  /* Shadows. Cards and panels are flat; shadows only appear at true
     overlay altitude (menu popup, dialog, tooltip, toast). Stacked
     triple fakes depth: 1px top edge for crispness, mid diffusion for
     the body of the lift, long soft drop for the cast. */
  --shadow-card:
    0 2px 2px rgba(0, 0, 0, 0.04);
  --shadow-menu:
    0 1px 1px rgba(0, 0, 0, 0.02),
    0 4px 8px -4px rgba(0, 0, 0, 0.04),
    0 16px 24px -8px rgba(0, 0, 0, 0.06);
  --shadow-modal:
    0 1px 1px rgba(0, 0, 0, 0.02),
    0 8px 16px -4px rgba(0, 0, 0, 0.04),
    0 24px 32px -8px rgba(0, 0, 0, 0.06);
  --shadow-tooltip: var(--shadow-menu);

  /* Motion. Two durations, one easing curve. */
  --duration-state:   75ms;
  --duration-overlay: 150ms;
  --ease-standard:    cubic-bezier(0.175, 0.885, 0.32, 1.1);

  /* Font families. Two families ship: one variable sans for everything
     that isn't code, one mono for code. Consumers ship the actual font
     files through their pipeline; the docs site loads Inter via
     next/font (which is now a variable font at all weights 100-900) and
     JetBrains Mono for code. --font-body-loaded / --font-mono-loaded
     come from next/font first; raw family names + system fallbacks
     follow. --font-display aliases --font-body: there is no separate
     display cut. Display sizes ride weight and size, not a distinct
     family or letter-spacing recipe. */
  --font-body:    var(--font-body-loaded), "Inter", -apple-system, system-ui, "Segoe UI", Roboto, sans-serif;
  --font-display: var(--font-body);
  --font-mono:    var(--font-mono-loaded), "JetBrains Mono", ui-monospace, "SF Mono", Menlo, monospace;

  /* Font sizes. Eight rem-based sizes cover every use, from the smallest
     meta label (micro, 11px) up to a page-hero heading (title1, 36px).
     Default body is regular (15px). Bundled leading, tracking, and
     weight are gone: line-height comes from element defaults (body 1.5,
     p 1.7, headings 1.25) and weight is a separate token axis below.
     Sub-Retina rounds micro up to a whole pixel to avoid subpixel blur
     on 1x displays. */
  --font-size-micro:    0.6875rem; /* 11 */
  --font-size-mini:     0.75rem;   /* 12 */
  --font-size-small:    0.8125rem; /* 13 */
  --font-size-regular:  0.9375rem; /* 15 */
  --font-size-large:    1.125rem;  /* 18 */
  --font-size-title3:   1.25rem;   /* 20 */
  --font-size-title2:   1.5rem;    /* 24 */
  --font-size-title1:   2.25rem;   /* 36 */

  /* Font weights. Body defaults to 450 (only available in variable fonts;
     non-variable Inter rounds to 400/500). Headings default to 500
     (medium). Weight is composed at the call site via Tailwind's
     font-{light,normal,medium,semibold,bold} utilities. */
  --font-weight-light:     300;
  --font-weight-normal:    450;
  --font-weight-medium:    500;
  --font-weight-semibold:  600;
  --font-weight-bold:      700;

  /* Spacing scale. Base unit 4px, every step a multiple. */
  --space-4:  4px;
  --space-8:  8px;
  --space-12: 12px;
  --space-16: 16px;
  --space-24: 24px;
  --space-32: 32px;
  --space-40: 40px;
  --space-64: 64px;
  --space-96: 96px;
}

/* ---------------------------------------------------------------
 * Dark-mode override. Same intent contract, inverted values.
 *
 * Neutral grays -- no blue/cool tint. Canvas is deliberately not pure
 * #000000: #0F0F10 keeps a warm-neutral read on OLED and prevents the
 * surface ladder from banding on cheap panels. surface-1 sits at the
 * "lifted popup" rung; surface-2 is the active-row highlight.
 *
 * Status roles are theme-invariant (no override); the -fg pair still
 * carries the same label color because meaning doesn't flip with theme.
 * --------------------------------------------------------------- */
.dark {
  /* Deeper base than the "just off-black" default so the perceptual
     range between base and layer-1 has room to breathe. Cool chroma
     is dialed back from earlier values: on a dark ground, even a
     small B-vs-R gap reads as visibly blue, so we run a much subtler
     lean here than the light-mode equivalents. */
  --base:      #0A0A0D;

  /* layer-1 is the default lifted panel (Card, Modal, Menu popup,
     Sheet, Tooltip, Input, secondary Button chrome). Sits ~3-4%
     lightness above base — enough to read as clearly separated but
     subtle enough that panels feel integrated with the dark ambient.
     Border and shadow do the rest of the elevation work. layer-2 is
     a hover step above layer-1. */
  --layer-1:   #191A1D;
  --layer-2:   #1F2023;

  /* fill-1 sits between base and layer-1 (subtle deeper tint for
     Toggle track, Switch off-track). fill-2 sits brighter than
     layer-1 so components rendered on a layer-1 surface (Table row
     hover, striped rows, Modal nested tile, Badge chip, Skeleton
     pulse, menu item highlight) still read distinct — collapsing
     fill-2 into layer-1 makes those states invisible in dark. */
  --fill-1:    #131418;
  --fill-2:    #232327;

  /* Overlays flip to white alpha in dark. Slightly stronger than light
     because white-on-dark reads more subtle than black-on-light at the
     same alpha. */
  --layer-hover:    rgba(255, 255, 255, 0.05);
  --layer-selected: rgba(255, 255, 255, 0.10);

  --hairline:           rgba(255, 255, 255, 0.06);
  --hairline-strong:    rgba(255, 255, 255, 0.11);
  --hairline-tertiary:  rgba(255, 255, 255, 0.18);

  --ink:           #F5F5F7;
  --ink-muted:     #9E9EA4;
  --ink-subtle:    #7C7C82;
  --ink-tertiary:  #6E6E74;

  /* Primary reinherits the inverted ink/canvas automatically through
     the var chain; the entries above already updated. Consumers that
     override --primary in light also override in dark. */

  /* --focus-ring-color inherits var(--primary), which now resolves to
     the dark-mode ink (#EDEDED) automatically -- no explicit dark-mode
     override needed. */

  /* Shadows deepen to compensate for reduced contrast on the near-black
     canvas. */
  --shadow-card:
    0 2px 2px rgba(0, 0, 0, 0.4);
  --shadow-menu:
    0 1px 1px rgba(0, 0, 0, 0.3),
    0 4px 8px -4px rgba(0, 0, 0, 0.4),
    0 16px 24px -8px rgba(0, 0, 0, 0.5);
  --shadow-modal:
    0 1px 1px rgba(0, 0, 0, 0.3),
    0 8px 16px -4px rgba(0, 0, 0, 0.4),
    0 24px 32px -8px rgba(0, 0, 0, 0.5);
}

/* Loading dots: 3 dots pulse in staggered sequence. */
@keyframes patch-dots-pulse {
  0%, 80%, 100% { opacity: 0.25; transform: scale(0.6); }
  40% { opacity: 1; transform: scale(1); }
}

/* Progress bar: indeterminate sweep from left to right. */
@keyframes patch-progress-indeterminate {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(400%); }
}

/* Skeleton placeholder: gentle opacity pulse. Range kept narrow so the
   block stays legibly present through the whole cycle. */
@keyframes patch-skeleton-pulse {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0.65; }
}

/* Reduced motion overrides both durations to 0ms; animations still
   fire but resolve instantly. */
@media (prefers-reduced-motion: reduce) {
  :root {
    --duration-state:   0ms;
    --duration-overlay: 0ms;
    --ease-standard:    ease;
  }
}

/* ---------------------------------------------------------------
 * Layer 2: Tailwind bridge (@theme inline).
 *
 * Exposes runtime tokens as Tailwind utility slots:
 *   - Every color as --color-* (bg-base, bg-layer-1, text-ink, border-hairline)
 *   - Every radius as --radius-*
 *   - Every shadow as --shadow-*
 *   - Motion easing as --ease-*
 *
 * Spacing lives at :root as --space-* only. Exposing --spacing-N here
 * would collide with Tailwind's h-N/p-N/gap-N default multiplier and
 * break sizing utilities.
 *
 * Type sizes are NOT exposed as --text-*; the compound utility classes
 * in Layer 3 already declare size + leading + tracking + weight +
 * font-family in one shot.
 * --------------------------------------------------------------- */
@theme inline {
  --color-base:    var(--base);
  --color-layer-1: var(--layer-1);
  --color-layer-2: var(--layer-2);
  --color-fill-1:  var(--fill-1);
  --color-fill-2:  var(--fill-2);

  --color-layer-hover:    var(--layer-hover);
  --color-layer-selected: var(--layer-selected);

  --color-hairline:           var(--hairline);
  --color-hairline-strong:    var(--hairline-strong);
  --color-hairline-tertiary:  var(--hairline-tertiary);

  --color-ink:           var(--ink);
  --color-ink-muted:     var(--ink-muted);
  --color-ink-subtle:    var(--ink-subtle);
  --color-ink-tertiary:  var(--ink-tertiary);

  --color-primary:        var(--primary);
  --color-primary-hover:  var(--primary-hover);
  --color-primary-active: var(--primary-active);
  --color-on-primary:     var(--on-primary);

  --color-error:         var(--error);
  --color-error-hover:   var(--error-hover);
  --color-error-active:  var(--error-active);
  --color-error-fg:      var(--error-fg);
  --color-warning:        var(--warning);
  --color-warning-hover:  var(--warning-hover);
  --color-warning-active: var(--warning-active);
  --color-warning-fg:     var(--warning-fg);
  --color-success:        var(--success);
  --color-success-hover:  var(--success-hover);
  --color-success-active: var(--success-active);
  --color-success-fg:     var(--success-fg);

  --color-scrim: var(--scrim);

  --radius-4:    var(--radius-4);
  --radius-6:    var(--radius-6);
  --radius-12:   var(--radius-12);
  --radius-16:   var(--radius-16);
  --radius-full: var(--radius-full);

  --shadow-card:    var(--shadow-card);
  --shadow-menu:    var(--shadow-menu);
  --shadow-modal:   var(--shadow-modal);
  --shadow-tooltip: var(--shadow-tooltip);

  --ease-standard: var(--ease-standard);

  --font-display: var(--font-display);
  --font-body:    var(--font-body);
  --font-mono:    var(--font-mono);

  /* Size utilities: text-micro / text-mini / text-small / text-regular /
     text-large / text-title3 / text-title2 / text-title1. */
  --text-micro:    var(--font-size-micro);
  --text-mini:     var(--font-size-mini);
  --text-small:    var(--font-size-small);
  --text-regular:  var(--font-size-regular);
  --text-large:    var(--font-size-large);
  --text-title3:   var(--font-size-title3);
  --text-title2:   var(--font-size-title2);
  --text-title1:   var(--font-size-title1);

  /* Weight utilities: overrides Tailwind's defaults so font-normal is
     450 (matching the variable-font body default) instead of 400. */
  --font-weight-light:    var(--font-weight-light);
  --font-weight-normal:   var(--font-weight-normal);
  --font-weight-medium:   var(--font-weight-medium);
  --font-weight-semibold: var(--font-weight-semibold);
  --font-weight-bold:     var(--font-weight-bold);
}

/* ---------------------------------------------------------------
 * Layer 3: Global element defaults for typography.
 *
 * Line height and default weight are set on the element, not bundled
 * into per-size utility classes. body is 1.5, <p> is 1.7, headings are
 * 1.25. font-family propagates through inheritance from body; form
 * controls need an explicit override because they reset by default.
 * --------------------------------------------------------------- */
@layer base {
  body {
    font-family: var(--font-body);
    font-size: var(--font-size-regular);
    font-weight: var(--font-weight-normal);
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
  }
  body,
  button,
  input,
  optgroup,
  select,
  textarea {
    font-family: var(--font-body);
  }
  p {
    line-height: 1.7;
  }
  h1, h2, h3, h4, h5, h6 {
    font-weight: var(--font-weight-medium);
    line-height: 1.25;
  }
  code, pre, kbd, samp {
    font-family: var(--font-mono);
  }
}

/* Sub-Retina rounding: on 1x displays the smallest size can land on a
   fractional pixel and blur. Snap it up to the nearest whole pixel via
   round(). Guarded on @supports so older engines fall through to the
   raw rem value. */
@supports (font-size: round(up, 1rem, 1px)) {
  @media not all and (-webkit-min-device-pixel-ratio: 2), not all and (min-resolution: 192dpi) {
    :root {
      --font-size-micro: round(up, 0.6875rem, 2px);
    }
  }
}

/* Opt an individual scrollable surface out of any scrollbar. Companion
 * to the global thin-scrollbar defaults below. Declared with @utility
 * so it participates in Tailwind variants (md:scrollbar-hide,
 * hover:scrollbar-hide, etc.). */
@utility scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
  &::-webkit-scrollbar {
    display: none;
  }
}

/* ---------------------------------------------------------------
 * Layer 4: base element styles.
 *
 * Thin, unobtrusive scrollbars applied globally. Thumb picks up
 * hairline-strong (0.13 alpha) and lifts to hairline-tertiary
 * (0.20 alpha) on hover, so it inverts naturally with the theme
 * without a per-mode override.
 *
 * Wrapped in @layer base so per-element consumer utilities (e.g.
 * [&::-webkit-scrollbar]:w-1) and unlayered overrides win the cascade
 * without needing !important. scrollbar-width and scrollbar-color are
 * inherited from :root; the ::-webkit-* pseudo-elements need the
 * wildcard since pseudo-elements don't inherit.
 * --------------------------------------------------------------- */
@layer base {
  :root {
    scrollbar-width: thin;
    scrollbar-color: var(--hairline-strong) transparent;
  }
  *::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  *::-webkit-scrollbar-track {
    background: transparent;
  }
  *::-webkit-scrollbar-thumb {
    background: var(--hairline-strong);
    border-radius: 999px;
  }
  *::-webkit-scrollbar-thumb:hover {
    background: var(--hairline-tertiary);
  }

  /* Icon default. Phosphor icons render with width="1em" / height="1em"
     attributes so they'd inherit the parent's font-size. Force a 1rem
     baseline here so an icon inside a text-small (13px) label still
     reads at 16px. Any Tailwind size-* class on the svg wins via
     selector specificity. */
  svg {
    width: 1rem;
    height: 1rem;
  }
}
